import { useState, useMemo } from 'react';
import './Listings.css';

const ITEMS = [
  { id: 1,  name: 'Folding Tables',        category: 'Furniture',    quantity: 120, location: 'Exposition Park',     condition: 'Good' },
  { id: 2,  name: 'Stadium Seats',          category: 'Furniture',    quantity: 350, location: 'SoFi Stadium',        condition: 'Like New' },
  { id: 3,  name: 'LED Lighting Rigs',      category: 'Electronics',  quantity: 80,  location: 'Crypto.com Arena',    condition: 'Good' },
  { id: 4,  name: 'Tents & Canopies',       category: 'Structures',   quantity: 45,  location: 'UCLA Campus',         condition: 'Like New' },
  { id: 5,  name: 'Crowd Control Fencing',  category: 'Structures',   quantity: 200, location: 'LAX Area',            condition: 'Fair' },
  { id: 6,  name: 'PA Audio Systems',       category: 'Electronics',  quantity: 30,  location: 'Pasadena',            condition: 'Good' },
  { id: 7,  name: 'Athlete Lockers',        category: 'Furniture',    quantity: 60,  location: 'Long Beach',          condition: 'Like New' },
  { id: 8,  name: 'Portable Generators',    category: 'Equipment',    quantity: 25,  location: 'El Monte',            condition: 'Good' },
  { id: 9,  name: 'Bleacher Sections',      category: 'Structures',   quantity: 18,  location: 'Rose Bowl',           condition: 'Fair' },
  { id: 10, name: 'Broadcast Cameras',      category: 'Electronics',  quantity: 12,  location: 'Hollywood Park',      condition: 'Like New' },
];

const CATEGORIES = ['All', ...Array.from(new Set(ITEMS.map((i) => i.category)))];

const CONDITION_COLORS = {
  'Like New': '#2e7d32',
  'Good':     '#1565c0',
  'Fair':     '#e65100',
};

export default function Listings() {
  const [search, setSearch]     = useState('');
  const [category, setCategory] = useState('All');

  const filtered = useMemo(() => {
    const q = search.toLowerCase();
    return ITEMS.filter((item) => {
      const matchesSearch =
        !q ||
        item.name.toLowerCase().includes(q) ||
        item.location.toLowerCase().includes(q);
      const matchesCategory = category === 'All' || item.category === category;
      return matchesSearch && matchesCategory;
    });
  }, [search, category]);

  return (
    <main className="listings-page">
      <div className="listings-header">
        <h1>Surplus Listings</h1>
        <p>Browse available materials from the LA28 Olympics.</p>
      </div>

      <div className="listings-controls">
        <input
          className="listings-search"
          type="search"
          placeholder="Search by name or location…"
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />
        <div className="listings-filters">
          {CATEGORIES.map((cat) => (
            <button
              key={cat}
              className={`filter-btn${category === cat ? ' active' : ''}`}
              onClick={() => setCategory(cat)}
            >
              {cat}
            </button>
          ))}
        </div>
      </div>

      {filtered.length === 0 ? (
        <p className="listings-empty">No items match your search.</p>
      ) : (
        <div className="listings-grid">
          {filtered.map((item) => (
            <div key={item.id} className="listing-card">
              <div className="card-top">
                <span className="card-category">{item.category}</span>
                <span
                  className="card-condition"
                  style={{ background: CONDITION_COLORS[item.condition] }}
                >
                  {item.condition}
                </span>
              </div>
              <h2 className="card-name">{item.name}</h2>
              <div className="card-meta">
                <div className="card-meta-row">
                  <span className="meta-label">Quantity</span>
                  <span className="meta-value">{item.quantity} units</span>
                </div>
                <div className="card-meta-row">
                  <span className="meta-label">Location</span>
                  <span className="meta-value">{item.location}</span>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </main>
  );
}
